ValidationRule.errorConditionFormula:
AND(
    /* 1. Detectamos si alguno de los campos de resumen ha cambiado */
    OR(
        ISCHANGED(Beneficios_principales__c),
        ISCHANGED(Promociones_asociadas__c)
    ),
    /* 2. Verificamos que NO sea una actualización del sistema (Apex) */
    Is_System_Update__c = false
)
